/**
 * 🎲 XUS AUDIO LOTTERY v3.3 — FIXED: lee del trigger, no del CEREBRO
 */

const input = $input.first().json;
const random = Math.random();
const AUDIO_PROBABILITY = 0.09;

// ═══ 1. OBTENER TEXTO — PRIMERO DEL TRIGGER ═══
let cerebroText = '';
try {
  const trigger = $('When Executed by Another Workflow').first().json;
  cerebroText = trigger.output || trigger.text || trigger.response || '';
  if (typeof cerebroText !== 'string') cerebroText = JSON.stringify(cerebroText);
} catch (e) {
  cerebroText = input.text || input.response || '';
}

// ═══ 2. DETECTAR [AUDIO_REQUESTED] ═══
const userRequestedAudio = cerebroText.includes('[AUDIO_REQUESTED]');

// ═══ 3. LIMPIAR TEXTO PARA AUDIO ═══
let audioText = cerebroText
    .replace(/\[AUDIO_REQUESTED\]\s*/gi, '')
    .replace(/\[MUSIC:[^\]]*\]\s*/gi, '')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/__([^_]+)__/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/#{1,6}\s*/g, '')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/•/g, ',')
    .replace(/\n{2,}/g, '. ')
    .replace(/\n/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();

const cleanText = cerebroText
    .replace(/\[AUDIO_REQUESTED\]\s*/gi, '')
    .trim();

// ═══ 4. DECISIÓN DE AUDIO ═══
const randomDecision = random < AUDIO_PROBABILITY;
const audioTextLen = audioText.length;
const hasUrl = /https?:\/\//.test(audioText);
const hasButton = cerebroText.includes('[MUSIC:');

let canSendAudio = false;
let blockedReason = null;

if (userRequestedAudio) {
    if (audioTextLen < 5) blockedReason = 'text_too_short_for_tts';
    else if (audioTextLen > 4500) blockedReason = 'text_exceeds_tts_limit';
    else canSendAudio = true;
} else if (randomDecision) {
    if (hasButton) blockedReason = 'has_music_buttons';
    else if (audioTextLen < 30) blockedReason = 'text_too_short';
    else if (audioTextLen > 2000) blockedReason = 'text_too_long';
    else if (hasUrl) blockedReason = 'contains_url';
    else canSendAudio = true;
} else {
    blockedReason = 'probability_not_met';
}

// ═══ 5. OUTPUT ═══
return [{
    json: {
        ...input,
        text: cleanText,
        audioText: audioText,
        sendAsAudio: canSendAudio,
        hasButton: hasButton,
        audioDecision: {
            randomValue: parseFloat(random.toFixed(4)),
            threshold: AUDIO_PROBABILITY,
            userRequested: userRequestedAudio,
            randomTriggered: randomDecision && !userRequestedAudio,
            finalDecision: canSendAudio,
            blockedReason: blockedReason,
            textLength: audioTextLen,
            mode: canSendAudio ? '🎙️ AUDIO_ELEVENLABS' : '📝 TEXT_STANDARD',
            trigger: userRequestedAudio ? '👤 USER_REQUESTED' :
                     (randomDecision ? '🎲 RANDOM_9%' : '📝 DEFAULT_TEXT')
        }
    }
}];

/**
 * 📊 SEND CONFIRMATION v2.1
 */
const sent = $input.first().json;
return [{
    json: {
        status: '✅ MENSAJE_ENVIADO',
        messageId: sent.message_id || sent.result?.message_id || 'N/A',
        chatId: sent.chat?.id || sent.result?.chat?.id || 'N/A',
        timestamp: new Date().toISOString(),
        _performance: { processingComplete: true, version: 'XUS_OUTPUT_v2.1_ELEVENLABS' }
    }
}];

/**
 * 🧠 XUS CONVERSATIONAL MEMORY ENGINE v10.0
 */

const input = $input.first().json;

const now = new Date(new Date().toLocaleString('en-US', {timeZone: 'America/Bogota'}));
const currentTimestamp = now.getTime();
const hour = now.getHours();
const minutes = now.getMinutes();
const dayOfWeek = now.toLocaleDateString('es-CO', { weekday: 'long' });
const dayNum = now.getDate();
const month = now.toLocaleDateString('es-CO', { month: 'long' });

const GREETING_COOLDOWN_MS = 10 * 60 * 1000;
const lastGreetingTimestamp = $execution?.customData?.lastGreeting || 0;
const timeSinceLastGreeting = currentTimestamp - lastGreetingTimestamp;
const shouldGreet = timeSinceLastGreeting > GREETING_COOLDOWN_MS;

let greeting = '', timeContext = '', energyLevel = '';

if (hour >= 5 && hour < 12) {
    greeting = shouldGreet ? ['Buenos días', 'Buen día', 'Qué tal esta mañana'][Math.floor(Math.random() * 3)] : '';
    timeContext = 'mañana'; energyLevel = hour < 7 ? 'temprano' : hour < 9 ? 'productiva' : 'avanzada';
} else if (hour >= 12 && hour < 14) {
    greeting = shouldGreet ? ['Buenas tardes', 'Qué tal', 'Hey'][Math.floor(Math.random() * 3)] : '';
    timeContext = 'mediodía'; energyLevel = 'almuerzo';
} else if (hour >= 14 && hour < 19) {
    greeting = shouldGreet ? ['Buenas tardes', 'Qué hay', 'Hey'][Math.floor(Math.random() * 3)] : '';
    timeContext = 'tarde'; energyLevel = hour < 16 ? 'post-almuerzo' : 'cierre';
} else if (hour >= 19 && hour < 22) {
    greeting = shouldGreet ? ['Buenas noches', 'Qué tal la noche', 'Hey'][Math.floor(Math.random() * 3)] : '';
    timeContext = 'noche'; energyLevel = 'relajado';
} else {
    greeting = shouldGreet ? ['Buenas noches', 'Aún despierto', 'Hey'][Math.floor(Math.random() * 3)] : '';
    timeContext = 'madrugada'; energyLevel = 'tranquilo';
}

const BANNED_PHRASES = ['pero ojo','ojo que','sin embargo','no obstante','por otro lado','en este sentido','cabe destacar','es importante mencionar','como te decía','básicamente','literalmente','sinceramente','honestamente','la verdad es que','para serte sincero','te cuento que','mira que','fíjate que','resulta que'];

const TRANSITION_ALTERNATIVES = [
    ['algo a tener presente', 'un detalle', 'eso sí', 'ahora', 'y bueno'],
    ['además', 'también', 'y', 'aparte', 'otra cosa'],
    ['aunque', 'si bien', 'y eso que', 'con todo', 'aun así'],
    ['la cosa es que', 'el punto es', 'lo clave aquí', 'lo importante'],
    ['entonces', 'así que', 'por eso', 'ahí está', 'ya con eso']
];

const sessionAlternatives = TRANSITION_ALTERNATIVES.map(group => group[Math.floor(Math.random() * group.length)]);

const originalText = input.text || input.audioText || '';
const lowerText = originalText.toLowerCase();

let contentType = 'general', contentContext = '', responseUrgency = 'normal';

const contentPatterns = [
    { type: 'reporte', patterns: ['ratio', 'progreso', '%', 'completados', 'análisis', 'estadística'], context: 'datos y métricas' },
    { type: 'confirmacion_habito', patterns: ['registrado', 'anotado', 'check', '✅', 'guardado', 'logrado'], context: 'confirmación de acción' },
    { type: 'agenda', patterns: ['agenda', 'evento', 'reunión', 'cita', 'calendario', 'horario'], context: 'organización temporal' },
    { type: 'email', patterns: ['correo', 'email', 'enviado', 'borrador', 'mensaje', 'mail'], context: 'comunicación email' },
    { type: 'musica', patterns: ['música', 'playlist', 'reproducir', '🎧', 'canción', 'spotify'], context: 'entretenimiento audio' },
    { type: 'motivacional', patterns: ['meta', 'objetivo', 'racha', '🔥', 'streak', 'logro'], context: 'motivación y metas' },
    { type: 'tarea', patterns: ['tarea', 'pendiente', 'todo', 'hacer', 'recordatorio'], context: 'gestión de tareas' },
    { type: 'salud', patterns: ['agua', 'sueño', 'ejercicio', 'meditación', 'salud'], context: 'bienestar personal' }
];

for (const pattern of contentPatterns) {
    if (pattern.patterns.some(p => lowerText.includes(p))) {
        contentType = pattern.type; contentContext = pattern.context; break;
    }
}

if (lowerText.includes('urgente') || lowerText.includes('rápido')) responseUrgency = 'quick';
else if (lowerText.includes('detalle') || lowerText.includes('análisis')) responseUrgency = 'detailed';

let keyData = { porcentaje: null, porcentajeInterpretacion: '', habitosCompletados: null, habitosTotales: null, racha: null, rachaInterpretacion: '', habitoNombre: null };

const porcentajeMatch = originalText.match(/(\d+)%/);
if (porcentajeMatch) {
    keyData.porcentaje = parseInt(porcentajeMatch[1]);
    keyData.porcentajeInterpretacion = keyData.porcentaje >= 90 ? 'excelente' : keyData.porcentaje >= 75 ? 'muy bueno' : keyData.porcentaje >= 60 ? 'bueno' : keyData.porcentaje >= 40 ? 'regular' : 'bajo';
}

const progresoMatch = originalText.match(/(\d+)\/(\d+)/);
if (progresoMatch) { keyData.habitosCompletados = parseInt(progresoMatch[1]); keyData.habitosTotales = parseInt(progresoMatch[2]); }

let emotionalTone = 'neutral', toneIntensity = 'medium', toneNotes = [];
if (keyData.porcentaje !== null) {
    if (keyData.porcentaje >= 85) { emotionalTone = 'celebratorio_sutil'; toneIntensity = 'high'; toneNotes.push('reconocer logro sin exagerar'); }
    else if (keyData.porcentaje >= 70) { emotionalTone = 'positivo'; toneNotes.push('reconocer buen trabajo'); }
    else if (keyData.porcentaje >= 50) { emotionalTone = 'neutral_constructivo'; toneNotes.push('informativo sin juicio'); }
    else { emotionalTone = 'motivador_suave'; toneIntensity = 'low'; toneNotes.push('animar sin presionar'); }
}
if (contentType === 'confirmacion_habito') { emotionalTone = 'confirmatorio'; toneNotes.push('breve y efectivo'); }
if (hour >= 22 || hour < 6) { toneIntensity = 'low'; toneNotes.push('voz más suave, es tarde/temprano'); }

const openers = ['Listo,', 'Hecho,', 'Ya,', 'Ahí está,', 'Dale,', 'Oye,', 'Mira,', 'Bien,', 'Ok,', 'Perfecto,', '', '', ''];
const closers = ['', '', '', 'Ahí me dices.', 'Cualquier cosa.', 'Estamos.', 'Ya sabes.', 'Eso es todo.', 'Seguimos.', 'Ahí estamos.', 'Para eso estoy.'];
const nameVariations = ['Santi', 'Santiago', 'Arquitecto', 'jefe', 'crack', '', '', '', '', ''];

return [{
    json: {
        originalText,
        audioText: input.audioText || originalText,
        chatId: input.chatId,
        timeContext: { greeting, shouldGreet, period: timeContext, energy: energyLevel, hour, minutes, dayOfWeek, dayNum, month, fullDate: `${dayOfWeek} ${dayNum} de ${month}`, isLateNight: hour >= 23 || hour < 5, isWeekend: ['sábado', 'domingo'].includes(dayOfWeek) },
        contentContext: { type: contentType, description: contentContext, urgency: responseUrgency, keyData },
        emotionalContext: { tone: emotionalTone, intensity: toneIntensity, notes: toneNotes },
        antiRepetition: { bannedPhrases: BANNED_PHRASES, sessionAlternatives, selectedOpener: openers[Math.floor(Math.random() * openers.length)], selectedCloser: closers[Math.floor(Math.random() * closers.length)], selectedName: nameVariations[Math.floor(Math.random() * nameVariations.length)] },
        userName: 'Santi',
        sessionId: `audio_${currentTimestamp}`,
        audioDecision: input.audioDecision
    }
}];

/**
 * 🔧 XUS AUDIO OUTPUT PROCESSOR v10.0
 */

const input = $input.first().json;
const contextData = $('🧠 XUS Memory Engine v10').first().json;

let humanizedText = input.text || input.response || input.output || '';

humanizedText = humanizedText
    .replace(/```[\s\S]*?```/g, '')
    .replace(/^["'`]|["'`]$/g, '')
    .replace(/[\u{1F300}-\u{1F9FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{1F600}-\u{1F64F}]|[\u{1F680}-\u{1F6FF}]/gu, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/[━═─┃│┌┐└┘├┤┬┴┼]+/g, '')
    .replace(/[-]{3,}/g, '').replace(/[=]{3,}/g, '')
    .replace(/\s+/g, ' ').replace(/\n+/g, ' ')
    .trim();

const bannedPhrases = contextData.antiRepetition?.bannedPhrases || [];
const alternatives = contextData.antiRepetition?.sessionAlternatives || [];
let foundBanned = [];

for (const banned of bannedPhrases) {
    if (humanizedText.toLowerCase().includes(banned.toLowerCase())) {
        foundBanned.push(banned);
        const replacement = alternatives[Math.floor(Math.random() * alternatives.length)] || '';
        humanizedText = humanizedText.replace(new RegExp(banned, 'gi'), replacement);
    }
}

const shouldGreet = contextData.timeContext?.shouldGreet;
const greetingPatterns = [/^buenas? (tardes?|días?|noches?)/i, /^buen día/i, /^hola/i, /^qué tal/i, /^hey/i, /^saludos/i];

if (shouldGreet === false) {
    for (const pattern of greetingPatterns) humanizedText = humanizedText.replace(pattern, '').trim();
    humanizedText = humanizedText.replace(/^(santi|santiago|arquitecto)[,.]?\s*/i, '').trim();
}

if (!humanizedText || humanizedText.length < 10) {
    const contentType = contextData.contentContext?.type || 'general';
    const opener = contextData.antiRepetition?.selectedOpener || 'Listo';
    switch (contentType) {
        case 'confirmacion_habito': humanizedText = `${opener}, quedó registrado.`; break;
        case 'reporte': humanizedText = `${opener}, aquí están los datos.`; break;
        case 'email': humanizedText = `${opener}, correo procesado.`; break;
        default: humanizedText = contextData.audioText || 'Mensaje procesado.';
    }
}

if (humanizedText.length > 2000) {
    const truncated = humanizedText.substring(0, 1950);
    const lastPeriod = truncated.lastIndexOf('.');
    humanizedText = lastPeriod > 1500 ? truncated.substring(0, lastPeriod + 1) : truncated + '...';
}

humanizedText = humanizedText
    .replace(/\b(Además|También|Y bueno|Ahora|Eso sí)\s/gi, '$1, ')
    .replace(/([.,!?])\1+/g, '$1')
    .replace(/\s+([.,!?])/g, '$1')
    .replace(/([.,!?])([A-Za-záéíóúñ])/g, '$1 $2')
    .trim();

humanizedText = humanizedText.charAt(0).toUpperCase() + humanizedText.slice(1);

return [{
    json: {
        humanizedText,
        chatId: contextData.chatId,
        originalText: contextData.originalText,
        audioDecision: contextData.audioDecision,
        metadata: {
            charCount: humanizedText.length,
            wordCount: humanizedText.split(/\s+/).length,
            bannedPhrasesFound: foundBanned,
            bannedPhrasesRemoved: foundBanned.length,
            greetingStatus: shouldGreet ? 'allowed' : 'removed',
            timeContext: contextData.timeContext?.period,
            contentType: contextData.contentContext?.type,
            emotionalTone: contextData.emotionalContext?.tone,
            sessionId: contextData.sessionId
        }
    }
}];

/**
 * 🎙️ AUDIO METADATA INJECTOR v10.0
 */

const items = $input.all();
const processorData = $('🔧 Audio Output Processor v10').first().json;

for (const item of items) {
    item.json.chatId = processorData.chatId;
    item.json.originalText = processorData.originalText;
    item.json.humanizedText = processorData.humanizedText;
    item.json.audioDecision = processorData.audioDecision;
    item.json.processingMetadata = processorData.metadata;
    if (item.binary && item.binary.data) {
        const timestamp = Date.now();
        const sessionId = processorData.metadata?.sessionId || timestamp;
        item.binary.data.fileName = `xus_voice_${sessionId}.mp3`;
        item.binary.data.mimeType = 'audio/mpeg';
    }
}

return items;

/**
 * ⚠️ INTELLIGENT AUDIO FALLBACK v10.1 — FIXED: conectado al error de ElevenLabs
 */

let processorData = {};
let chatId = '';

try {
  processorData = $('🔧 Audio Output Processor v10').first().json;
  chatId = processorData.chatId || '';
} catch(e) {}

// Si no tenemos chatId del processor, leerlo del trigger
if (!chatId) {
  const t = $('When Executed by Another Workflow').first().json;
  chatId = (t.chatId || t.message?.chat?.id || t.callback_query?.message?.chat?.id || '').toString();
}

let fallbackText = processorData.humanizedText || processorData.originalText || '';

// Si no hay texto del processor, intentar del trigger
if (!fallbackText) {
  const t = $('When Executed by Another Workflow').first().json;
  fallbackText = t.output || t.text || t.response || '⚠️ Error procesando respuesta.';
  fallbackText = fallbackText
    .replace(/\[AUDIO_REQUESTED\]\s*/gi, '')
    .replace(/\[MUSIC:[^\]]*\]/gi, '')
    .trim();
}

fallbackText += '\n\n_🎙️ Audio temporalmente no disponible_';

return [{
    json: {
        chatId,
        text: fallbackText,
        parse_mode: 'Markdown',
        fallbackReason: 'elevenlabs_error',
        originalMetadata: processorData.metadata || {}
    }
}];

/**
 * 🎯 MESSAGE BUILDER v3.1 — HTML MODE
 */

const aggregated = $input.first().json;
const response = aggregated.response;

let text = response.textResponse || response.message || 'Procesado.';

text = text
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/\*\*([^*]+)\*\*/g, '<b>$1</b>')
  .replace(/\*([^*]+)\*/g, '<b>$1</b>')
  .replace(/_([^_]+)_/g, '<i>$1</i>')
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  .replace(/^\* /gm, '• ').replace(/^- /gm, '• ')
  .replace(/^#{1,6}\s*/gm, '');

text = text.substring(0, 4096);

const telegramPayload = {
  chat_id: aggregated.chatId,
  text: text,
  parse_mode: 'HTML'
};

if (aggregated.hasButtons && aggregated.buttonConfig?.inlineKeyboard) {
  telegramPayload.reply_markup = { inline_keyboard: aggregated.buttonConfig.inlineKeyboard };
}

return [{ json: telegramPayload }];

