/**
 * 📊 RESPONSE AGGREGATOR v12.1 — FIXED: lee del trigger, no del CEREBRO
 */

// ═══ CHAT ID ═══
let chatId = '';
try {
  const t = $('When Executed by Another Workflow').first().json;
  chatId = (
    t.chatId ||
    t.callback_query?.message?.chat?.id ||
    t.message?.chat?.id ||
    t.chat?.id ||
    ''
  ).toString();
} catch(e) {}

if (!chatId) {
  return [{ json: { chatId: '', response: { moduleType: 'error', textResponse: '⚠️ No chat ID' }, hasButtons: false } }];
}

// ═══ TEXTO — LEER DEL TRIGGER (viene del Context Injector del cluster) ═══
let responseText = '';
let rawCerebro = '';

try {
  const trigger = $('When Executed by Another Workflow').first().json;
  rawCerebro = trigger.output || trigger.text || trigger.response || '';
  if (typeof rawCerebro !== 'string') rawCerebro = JSON.stringify(rawCerebro);
  responseText = rawCerebro;
} catch(e) {
  responseText = '⚠️ Error procesando respuesta.';
}

// ═══ PLAYLISTS ═══
const PLAYLISTS = {
  IMP: { url: 'https://music.youtube.com/watch?v=YlbvZ542Ijo&list=PLHB0xXYYWtksB2H0QehkY-AFWfP9ATLtA', name: 'Imperial Mode', emoji: '🌌' },
  USD: { url: 'https://music.youtube.com/watch?v=ibonMtKGPRM&list=PLHB0xXYYWtksOeB3kOrg3ssVb3LL0cJpD', name: 'Deep Work', emoji: '🧠' }
};

let hasButtons = false, inlineKeyboard = null, moduleType = 'chat';

// ═══ 1. DETECTAR MENÚ ═══
let normalizedRaw = rawCerebro
  .replace(/callbackdata/gi, 'callback_data')
  .replace(/: True/g, ': true').replace(/: False/g, ': false')
  .replace(/: None/g, ': null').replace(/'/g, '"');

if (normalizedRaw.includes('menuButtons') || normalizedRaw.includes('menu_buttons')) {
  try {
    const firstBrace = normalizedRaw.indexOf('{');
    const lastBrace = normalizedRaw.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1) {
      let parsed = JSON.parse(normalizedRaw.substring(firstBrace, lastBrace + 1));
      function findMenuButtons(obj) {
        if (!obj || typeof obj !== 'object') return null;
        if (obj.menuButtons && Array.isArray(obj.menuButtons)) return obj;
        for (const key of Object.keys(obj)) {
          const val = obj[key];
          if (Array.isArray(val)) { for (const item of val) { const found = findMenuButtons(item); if (found) return found; } }
          else if (typeof val === 'object' && val !== null) { const found = findMenuButtons(val); if (found) return found; }
        }
        return null;
      }
      const menuData = findMenuButtons(parsed);
      if (menuData && menuData.menuButtons) {
        hasButtons = true; moduleType = 'menu';
        responseText = menuData.textResponse || '*📋 Menú*';
        inlineKeyboard = menuData.menuButtons.map(row => {
          if (!Array.isArray(row)) return row;
          return row.map(btn => { const clean = { text: btn.text }; if (btn.callback_data) clean.callback_data = btn.callback_data; if (btn.url) clean.url = btn.url; return clean; });
        });
      }
    }
  } catch(e) {}
}

// ═══ 2. DETECTAR [MUSIC:TAG] ═══
if (!hasButtons) {
  const musicMatch = responseText.match(/\[MUSIC:([^\]]+)\]/);
  if (musicMatch) {
    const tag = musicMatch[1]; moduleType = 'music';
    if (tag === 'IMP' || tag === 'USD') {
      const pl = PLAYLISTS[tag]; hasButtons = true;
      inlineKeyboard = [
        [{ text: pl.emoji + ' Abrir ' + pl.name, url: pl.url }],
        [{ text: '⏸️ Pausar', callback_data: 'music_pause' }, { text: '⏭️ Skip', callback_data: 'music_skip' }],
        [{ text: '🔊 Vol+', callback_data: 'music_vol_up' }, { text: '🔉 Vol-', callback_data: 'music_vol_down' }]
      ];
    } else if (tag.startsWith('SEARCH:')) {
      const url = tag.replace('SEARCH:', '').trim();
      if (url.startsWith('http')) {
        hasButtons = true;
        inlineKeyboard = [
          [{ text: '🎵 Escuchar', url }],
          [{ text: '⏸️ Pausar', callback_data: 'music_pause' }, { text: '⏭️ Skip', callback_data: 'music_skip' }],
          [{ text: '🔊 Vol+', callback_data: 'music_vol_up' }, { text: '🔉 Vol-', callback_data: 'music_vol_down' }]
        ];
      }
    }
  }
}

// ═══ 3. LIMPIAR TEXTO ═══
if (moduleType !== 'menu') {
  responseText = responseText
    .replace(/\[MUSIC:[^\]]*\]/gi, '').replace(/\[AUDIO_REQUESTED\]\s*/gi, '')
    .replace(/```json\s*/gi, '').replace(/```\s*/gi, '')
    .replace(/\*\*([^*]+)\*\*/g, '*$1*').replace(/^#{1,6}\s*/gm, '')
    .replace(/^\* /gm, '• ').replace(/^- /gm, '• ')
    .replace(/\n{4,}/g, '\n\n\n').trim();
}

responseText = responseText.substring(0, 4096);
if (!responseText) responseText = '✅ Procesado.';

return [{ json: {
  chatId,
