const xusRequestedReact = cerebroText.includes('[REACT]');
const text = cerebroText.toLowerCase();

const reactContexts = [
  /registrado|anotado|completado|guardado|hecho|listo/,
  /✅|🔥|💪|⚡/,
  /racha|streak|logro/,
  /cerré|agendé|pagaron|ingreso/,
  /correo enviado|evento creado|recordatorio/
];

const noReactContexts = [
  /\?/, /\[MUSIC:/, /menuButtons/, /reporte|análisis|estadístic/
];

const contextTrigger = reactContexts.some(p => p.test(text));
const contextBlock = noReactContexts.some(p => p.test(text));
const randomReact = Math.random() < 0.15;

const shouldReact = xusRequestedReact || (contextTrigger && !contextBlock) || (!contextBlock && randomReact);

return [{ json: {
  ...input,
  shouldReact,
  reactReason: xusRequestedReact ? 'xus_requested' : contextTrigger ? 'context_trigger' : randomReact ? 'random_15%' : 'no_react'
} }];

